class Solution:
    def numberOfWays(self, n: int, x: int, y: int) -> int:
        MOD = 10**9 + 7
        dp = [1] * (x + 1)
        for _ in range(n):
            dp2 = [0] * (x + 1)
            for i in range(1, x + 1):
                dp2[i] = (dp2[i - 1] * (i - 1) + dp[i]) % MOD
            dp = dp2
        res = 1
        for i in range(1, x + 1):
            res = (res * (y ** i)) % MOD
        return res

